import { useEffect, useState } from "react";

export default function SystemStats() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setTimeout(() => {
      setStats({
        uptime: 240,
        capture: { kernel_packets: 1024 },
        flow: { tcp: 12 },
        detect: { alert: 5, alert_queue_overflow: 1 },
      });
      setLoading(false);
    }, 500);
  }, []);

  if (loading) return <p className="text-gray-500">Ładowanie statystyk systemu...</p>;

  return (
    <div className="grid gap-6 grid-cols-1 sm:grid-cols-2 lg:grid-cols-3">
      <StatCard label="⏱️ Uptime (s)" value={stats.uptime} />
      <StatCard label="📦 Pakiety z jądra" value={stats.capture?.kernel_packets ?? 0} />
      <StatCard label="🌐 Sesje TCP" value={stats.flow?.tcp ?? 0} />
      <StatCard label="🚨 Liczba alertów" value={stats.detect?.alert ?? 0} />
      <StatCard label="⚠️ Alert Queue Overflow" value={stats.detect?.alert_queue_overflow ?? 0} />
    </div>
  );
}

function StatCard({ label, value }) {
  return (
    <div className="bg-white rounded-xl shadow-md p-6 border-l-4 border-green-500">
      <h3 className="text-sm text-gray-600">{label}</h3>
      <p className="text-3xl font-semibold text-gray-800 mt-2">{value}</p>
    </div>
  );
}
